export function initialize(sentinel, dotNetHelper) {
    const observer = new IntersectionObserver(entries => {
        if (entries[0].isIntersecting) {
            dotNetHelper.invokeMethodAsync("OnSentinelVisible");
        }
    }, { rootMargin: "200px" });

    observer.observe(sentinel);

    return { observer, sentinel };
}

export function dispose(instance) {
    if (instance?.observer) {
        instance.observer.unobserve(instance.sentinel);
        instance.observer.disconnect();
    }
}

@typeparam TItem
@implements IAsyncDisposable
@inject IJSRuntime JS

<div class="infinite-scroll-container">
    @foreach (var item in Items)
    {
        @ChildContent(item)
    }

    @if (HasMore)
    {
        <div @ref="sentinelRef" class="sentinel">
            @if (isLoading)
            {
                <div class="loading-spinner" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            }
        </div>
    }
</div>

@code {
    /// <summary>The collection of items to display.</summary>
    [Parameter, EditorRequired]
    public IReadOnlyList<TItem> Items { get; set; } = [];

    /// <summary>Template for rendering each item.</summary>
    [Parameter, EditorRequired]
    public RenderFragment<TItem> ChildContent { get; set; } = default!;

    /// <summary>Whether additional items are available to load.</summary>
    [Parameter]
    public bool HasMore { get; set; }

    /// <summary>Callback invoked when the user scrolls near the bottom.</summary>
    [Parameter, EditorRequired]
    public EventCallback OnLoadMore { get; set; }

    private ElementReference sentinelRef;
    private IJSObjectReference? module;
    private IJSObjectReference? observerInstance;
    private DotNetObjectReference<InfiniteScrollList<TItem>>? dotNetRef;
    private bool isLoading;
    private bool hasMounted;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            hasMounted = true;
            await SetupObserver();
        }
    }

    public override async Task SetParametersAsync(ParameterView parameters)
    {
        var previousHasMore = HasMore;
        await base.SetParametersAsync(parameters);

        // Re-attach the observer when HasMore flips back to true after being false
        if (hasMounted && HasMore && !previousHasMore)
        {
            await SetupObserver();
        }
    }

    private async Task SetupObserver()
    {
        await DisposeObserver();

        if (!HasMore) return;

        module ??= await JS.InvokeAsync<IJSObjectReference>(
            "import", "./js/infinite-scroll.js");

        dotNetRef = DotNetObjectReference.Create(this);
        observerInstance = await module.InvokeAsync<IJSObjectReference>(
            "initialize", sentinelRef, dotNetRef);
    }

    [JSInvokable]
    public async Task OnSentinelVisible()
    {
        if (isLoading || !HasMore) return;

        isLoading = true;
        StateHasChanged();

        await OnLoadMore.InvokeAsync();

        isLoading = false;
        StateHasChanged();
    }

    private async ValueTask DisposeObserver()
    {
        if (observerInstance is not null && module is not null)
        {
            await module.InvokeVoidAsync("dispose", observerInstance);
            observerInstance = null;
        }
        dotNetRef?.Dispose();
        dotNetRef = null;
    }

    public async ValueTask DisposeAsync()
    {
        await DisposeObserver();

        if (module is not null)
        {
            await module.DisposeAsync();
        }
    }
}

.infinite-scroll-container {
    overflow-y: auto;
}

.sentinel {
    display: flex;
    justify-content: center;
    padding: 1rem 0;
    min-height: 1px;
}

.loading-spinner {
    width: 2rem;
    height: 2rem;
    border: 0.25rem solid #e0e0e0;
    border-top-color: #0d6efd;
    border-radius: 50%;
    animation: spin 0.75s linear infinite;
}

@keyframes spin {
    to { transform: rotate(360deg); }
}

